{action_set_definitions}: {
  "get_vertical_profile": {
    "description": "Retrieves water temperature and dissolved oxygen (DO) levels at specific depths to identify stratification and oxygen deficits.",
    "parameters": {
      "type": "object",
      "properties": {
        "depths": {
          "type": "array",
          "items": {
            "type": "number"
          },
          "description": "A list of depths (in meters) at which to take measurements."
        }
      },
      "required": [
        "depths"
      ]
    },
    "example_output": {
      "measurements": [
        {
          "depth": 0.5,
          "temperature": 22.1,
          "dissolved_oxygen": 6.5
        },
        {
          "depth": 5.1,
          "temperature": 19.5,
          "dissolved_oxygen": 3.2
        }
      ]
    }
  },
  "get_water_chemistry": {
    "description": "Measures pH and ammonia concentration at a specific depth, essential for monitoring toxic metabolite levels in the hypolimnion.",
    "parameters": {
      "type": "object",
      "properties": {
        "depth": {
          "type": "number",
          "description": "The depth in meters to sample the water chemistry."
        }
      },
      "required": [
        "depth"
      ]
    },
    "example_output": {
      "ph_level": 7.2,
      "ammonia_concentration": 0.04
    }
  },
  "get_system_status": {
    "description": "Retrieves the current basin metadata, equipment statuses, and last feeding time.",
    "parameters": {
      "type": "object",
      "properties": {}
    },
    "example_output": {
      "water_level": 5.2,
      "aerator_status": "low",
      "heater_status": "off",
      "last_feeding_time": "2 hours ago"
    }
  },
  "configure_mixing_and_aeration": {
    "description": "Adjusts the aeration system mode and mechanical mixing intensity to homogenize the basin.",
    "parameters": {
      "type": "object",
      "properties": {
        "aerator_mode": {
          "type": "string",
          "enum": [
            "off",
            "low",
            "medium",
            "high"
          ],
          "description": "Target status of the oxygenation system."
        },
        "mixing_intensity": {
          "type": "integer",
          "minimum": 0,
          "maximum": 100,
          "description": "Mechanical mixing power as a percentage (0-100%)."
        }
      },
      "required": [
        "aerator_mode",
        "mixing_intensity"
      ]
    },
    "example_output": {
      "status": "applied",
      "aerator_mode": "high",
      "mixing_intensity": 50
    }
  },
  "manage_feeding": {
    "description": "Controls the feeding regime to manage Biological Oxygen Demand (BOD) based on the identified risk level.",
    "parameters": {
      "type": "object",
      "properties": {
        "regime": {
          "type": "string",
          "enum": [
            "normal",
            "reduced",
            "suspended"
          ],
          "description": "The feeding strategy to implement."
        }
      },
      "required": [
        "regime"
      ]
    },
    "example_output": {
      "status": "updated",
      "current_regime": "suspended"
    }
  }
}
